test('form validation', async ({ page }) => {
  // 1. Assert email error is visible (initially)
  // 2. Assert password hint is visible
  // 3. Assert submit button is disabled
  // 4. Fill valid email & password
  // 5. Assert submit button is enabled
});

challenges.solution:
import { test, expect } from '@playwright/test';

test('form validation', async ({ page }) => {
  await expect(page.getByText('Invalid email format')).toBeVisible();
  await expect(page.getByText('Must be 8+ characters')).toBeVisible();
  await expect(page.getByRole('button', { name: 'Register' })).toBeDisabled();

  await page.getByPlaceholder('Enter email').fill('test@test.com');
  await page.getByPlaceholder('8+ characters').fill('password123');

  await expect(page.getByRole('button', { name: 'Register' })).toBeEnabled();
});
